"use client";
import { FormEvent, useEffect, useState } from "react";
import VendorSidebar from "../sidebar";
import { AvailabilitySlot, createAvailability, deleteAvailability, getAvailability } from "../../../../lib/vendor-api";
export default function VendorAvailability(){const [slots,setSlots]=useState<AvailabilitySlot[]>([]);const [start,setStart]=useState("");const [end,setEnd]=useState("");const [error,setError]=useState("");const [notice,setNotice]=useState("");const [loading,setLoading]=useState(true);const [saving,setSaving]=useState(false);const today=new Date().toISOString().slice(0,10);const load=()=>{setLoading(true);getAvailability().then(d=>{setSlots(d.availability.filter(s=>!s.isAvailable));setError("");}).catch(e=>setError(e.message||"Unable to load availability.")).finally(()=>setLoading(false));};useEffect(load,[]);async function submit(e:FormEvent){e.preventDefault();if(start<today||end<start){setError("Choose a valid date range starting today or later.");return;}if(slots.some(s=>start===s.startsAt.slice(0,10)&&end===new Date(new Date(s.endsAt).getTime()-86400000).toISOString().slice(0,10))){setError("That unavailable date range is already listed.");return;}setSaving(true);try{const endDate=new Date(`${end}T00:00:00Z`);endDate.setUTCDate(endDate.getUTCDate()+1);const d=await createAvailability({startsAt:`${start}T00:00:00.000Z`,endsAt:endDate.toISOString(),isAvailable:false});setSlots(x=>[...x,d.availability]);setStart("");setEnd("");setNotice("Dates blocked. Customers cannot submit a request for this period.");setError("");}catch(e:any){setError(e.message||"Unable to block dates.");}finally{setSaving(false);}}async function remove(slot:AvailabilitySlot){if(!window.confirm("Remove this blocked date range?"))return;try{await deleteAvailability(slot.id);setSlots(x=>x.filter(s=>s.id!==slot.id));setNotice("Blocked dates removed.");}catch(e:any){setError(e.message||"Unable to remove dates.");}}return <div className="min-h-screen bg-[#fffdfc] md:flex"><VendorSidebar/><main className="flex-1 p-5 pt-20 md:p-10"><p className="text-sm font-bold uppercase tracking-[.16em] text-[#8B000F]">Vendor workspace</p><h1 className="mt-2 font-serif text-4xl font-bold text-[#5c1632]">Availability</h1><p className="mt-2 text-slate-600">Block dates when you cannot accept booking requests. Blocking a date does not confirm a booking.</p>{notice&&<p role="status" className="mt-5 rounded-xl bg-emerald-50 p-4 text-emerald-800">{notice}</p>}{error&&<p role="alert" className="mt-5 rounded-xl bg-red-50 p-4 text-red-800">{error}</p>}<form onSubmit={submit} className="mt-7 flex flex-col gap-4 rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm sm:flex-row sm:items-end"><div><label htmlFor="block-start" className="mb-2 block text-sm font-semibold">Start date</label><input id="block-start" required min={today} type="date" value={start} onChange={e=>setStart(e.target.value)} className="rounded-xl border border-[#e7d4ce] px-4 py-3"/></div><div><label htmlFor="block-end" className="mb-2 block text-sm font-semibold">End date</label><input id="block-end" required min={start||today} type="date" value={end} onChange={e=>setEnd(e.target.value)} className="rounded-xl border border-[#e7d4ce] px-4 py-3"/></div><button disabled={saving} className="rounded-xl bg-[#8B000F] px-5 py-3 font-semibold text-white disabled:opacity-60">{saving?"Blocking…":"Block dates"}</button></form><section className="mt-8"><h2 className="text-xl font-bold text-[#6b1839]">Blocked dates</h2><div className="mt-4 grid gap-3">{loading?Array.from({length:3}).map((_,i)=><div key={i} className="h-16 animate-pulse rounded-xl bg-slate-100"/>):slots.map(s=><article key={s.id} className="flex flex-col justify-between gap-3 rounded-xl border border-[#f0ded8] bg-white p-4 sm:flex-row sm:items-center"><p><strong>Unavailable:</strong> {s.startsAt.slice(0,10)} to {new Date(new Date(s.endsAt).getTime()-86400000).toISOString().slice(0,10)}</p><button onClick={()=>remove(s)} className="w-fit rounded-lg border border-red-300 px-3 py-2 text-sm font-semibold text-red-700">Remove</button></article>)}{!loading&&!slots.length&&<div className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-8 text-slate-600">No blocked dates. Customers may send requests for future dates, subject to your review.</div>}</div></section></main></div>}
